SELECT baseline."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption" FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline WHERE baseline.applicability = true AND baseline."in.state" = 'CO' AND baseline.bldg_id IN (SELECT upgrade.bldg_id FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade WHERE upgrade.upgrade IN (1) AND upgrade.applicability = true GROUP BY upgrade.bldg_id HAVING count(distinct(upgrade.upgrade)) = 1) GROUP BY 1 ORDER BY 1